// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Voting {

    address public authority;
    bool public electionActive;
    uint public electionEndTime;

    struct Candidate {
        string name;
        uint voteCount;
    }

    Candidate[] public candidates;

    mapping(address => bool) public isRegistered;
    mapping(address => bool) public hasVoted;
    mapping(bytes32 => bool) public usedCommitments;

    bytes[] public encryptedVotes; // stores RSA encrypted ballots

    event VoterRegistered(address voter);
    event VoteCasted(address indexed voter, bytes32 commitment);
    event ElectionStarted(uint endTime);
    event ElectionEnded();

    modifier onlyAuthority() {
        require(msg.sender == authority, "Not authority");
        _;
    }

    modifier electionOngoing() {
        require(electionActive, "Election not active");
        require(block.timestamp < electionEndTime, "Election ended");
        _;
    }

    constructor() {
        authority = msg.sender;
    }

    // Authority registers voters
    function registerVoter(address voter) public onlyAuthority {
        require(!isRegistered[voter], "Already registered");
        isRegistered[voter] = true;
        emit VoterRegistered(voter);
    }

    // Authority adds candidates
    function addCandidate(string memory name) public onlyAuthority {
        candidates.push(Candidate(name, 0));
    }

    // Authority starts election with duration in seconds
    function startElection(uint durationSeconds) public onlyAuthority {
        require(!electionActive, "Already active");
        electionActive = true;
        electionEndTime = block.timestamp + durationSeconds;
        emit ElectionStarted(electionEndTime);
    }

    // Core vote function — ECC verified via msg.sender, RSA ciphertext stored
    function castVote(
        bytes memory encryptedBallot,
        bytes32 commitment
    ) public electionOngoing {

        require(isRegistered[msg.sender], "Not registered");
        require(!hasVoted[msg.sender], "Already voted");
        require(!usedCommitments[commitment], "Commitment reused");

        // Verify commitment matches the encrypted ballot
        require(
            keccak256(encryptedBallot) == commitment,
            "Commitment mismatch"
        );

        hasVoted[msg.sender] = true;
        usedCommitments[commitment] = true;
        encryptedVotes.push(encryptedBallot);

        emit VoteCasted(msg.sender, commitment);
    }

    // Authority ends election manually
    function endElection() public onlyAuthority {
        electionActive = false;
        emit ElectionEnded();
    }

    // Publish final tally after decryption (authority submits results)
    function publishResults(uint[] memory voteCounts) public onlyAuthority {
        require(!electionActive, "Election still active");
        require(voteCounts.length == candidates.length, "Count mismatch");
        for (uint i = 0; i < candidates.length; i++) {
            candidates[i].voteCount = voteCounts[i];
        }
    }

    // Fetch all encrypted votes for decryption
    function getEncryptedVotes() public view returns (bytes[] memory) {
        return encryptedVotes;
    }

    // Fetch all candidates
    function getCandidates() public view returns (Candidate[] memory) {
        return candidates;
    }

    function getTotalVotes() public view returns (uint) {
        return encryptedVotes.length;
    }
}

